sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {

    if (isLoading || !newValue)
        return;

    // Documentation Section

    g_form.setSectionDisplay(
        'documentation_verification',
        newValue == 'x_documentation_verification'
    );

    // Payment Section

    g_form.setSectionDisplay(
        'payment_information',
        newValue == 'x_loan_servicing'
    );

    // When entering Loan Servicing,
    // remove backward stages permanently for this session

    if (newValue == 'x_loan_servicing') {

        g_form.removeOption(
            'loan_stage',
            'x_loan_inquiry'
        );

        g_form.removeOption(
            'loan_stage',
            'x_documentation_verification'
        );

        g_form.removeOption(
            'loan_stage',
            'x_loan_underwriting'
        );

        g_form.removeOption(
            'loan_stage',
            'x_loan_approval_sanction Loan'
        );

    }

}
